import React from 'react';
import { Outlet, Link, useLocation } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const StaffLayout = () => {
  const { user, logout } = useAuth();
  const { staffList } = useData();
  const location = useLocation();

  // Lấy dữ liệu user mới nhất để hiển thị Job Title realtime
  const currentUser = staffList.find(s => s.id === user?.id) || user;

  const isActive = (path) => location.pathname === path ? 
    { background: '#003366', color: 'white' } : { color: '#333' };

  return (
    <div style={{ display: 'flex', minHeight: '100vh', flexDirection: 'column' }}>
      {/* Header Mobile & Desktop */}
      <header style={{ background: '#fff', padding: '10px 20px', boxShadow: '0 2px 5px rgba(0,0,0,0.05)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
            <img src="/logo192.png" alt="Logo" style={{height: '40px'}} />
            <div>
                <h3 style={{ margin: 0, color: '#003366' }}>BeAble VN</h3>
                {/* HIỂN THỊ JOB TITLES TẠI ĐÂY */}
                <small style={{ color: '#666', fontSize: '0.75rem' }}>
                    {currentUser?.jobTitles?.length > 0 
                        ? currentUser.jobTitles.join(' | ') 
                        : 'Staff Member'}
                </small>
            </div>
        </div>
        <button onClick={logout} style={{ background: '#f8f9fa', border: '1px solid #ddd', padding: '5px 10px', borderRadius: '4px', cursor: 'pointer' }}>
          Đăng xuất
        </button>
      </header>

      {/* Navigation Bar (Bottom on Mobile, Top/Side on Desktop - Simplistic version) */}
      <nav style={{ background: '#f1f3f5', padding: '10px', display: 'flex', gap: '10px', overflowX: 'auto', whiteSpace: 'nowrap' }}>
        <Link to="/staff/tasks" style={{ textDecoration: 'none', padding: '8px 15px', borderRadius: '20px', fontSize: '0.9rem', ...isActive('/staff/tasks') }}>
            📋 Công việc
        </Link>
        <Link to="/staff/checkin" style={{ textDecoration: 'none', padding: '8px 15px', borderRadius: '20px', fontSize: '0.9rem', ...isActive('/staff/checkin') }}>
            📍 Chấm công
        </Link>
        <Link to="/staff/facility" style={{ textDecoration: 'none', padding: '8px 15px', borderRadius: '20px', fontSize: '0.9rem', ...isActive('/staff/facility') }}>
            🧹 Cơ sở vật chất
        </Link>
        <Link to="/staff/performance" style={{ textDecoration: 'none', padding: '8px 15px', borderRadius: '20px', fontSize: '0.9rem', ...isActive('/staff/performance') }}>
            💰 Lương & Hiệu suất
        </Link>
      </nav>

      {/* Content Area */}
      <main style={{ flex: 1, padding: '15px', background: '#f8f9fa' }}>
        <Outlet />
      </main>
    </div>
  );
};

export default StaffLayout;
